-.416-.287-.807-.415l-1.157-.36c-.583-.183-1.014-.454-1.277-.813a1.902 1.902 0 0 1-.4-1.158c0-.335.073-.63.216-.886.144-.255.335-.479.575-.654.24-.184.51-.32.83-.415.32-.096.655-.136 1.006-.136.175 0 .359.008.535.032.183.024.35.056.518.088.16.04.312.08.455.127.144.048.256.096.336.144a.69.69 0 0 1 .24.2.43.43 0 0 1 .071.263v.375c0 .168-.064.256-.184.256a.83.83 0 0 1-.303-.096 3.652 3.652 0 0 0-1.532-.311c-.455 0-.815.071-1.062.223-.248.152-.375.383-.375.71 0 .224.08.416.24.567.159.152.454.304.877.44l1.134.358c.574.184.99.44 1.237.767.247.327.367.702.367 1.117 0 .343-.072.655-.207.926-.144.272-.336.511-.583.703-.248.2-.543.343-.886.447-.36.111-.743.167-1.142.167zM21.698 16.207c-2.626 1.94-6.442 2.969-9.722 2.969-4.598 0-8.74-1.7-11.87-4.526-.247-.223-.024-.527.272-.351 3.384 1.963 7.559 3.153 11.877 3.153 2.914 0 6.114-.607 9.06-1.852.439-.2.814.287.383.607z"/>
    <path fill="#FF9900" d="M22.792 14.961c-.336-.43-2.22-.207-3.074-.103-.255.032-.295-.192-.063-.36 1.5-1.053 3.967-.75 4.254-.399.287.36-.08 2.826-1.485 4.007-.215.184-.423.088-.327-.151.32-.79 1.03-2.57.695-2.994z"/>
  </svg>
);

const AzureIcon: React.FC = () => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 96 96" width="36" height="36">
    <defs>
      <linearGradient id="az-grad-1" x1="-1032.172" y1="145.312" x2="-1059.213" y2="65.426" gradientTransform="matrix(1 0 0 -1 1075 158)" gradientUnits="userSpaceOnUse">
        <stop offset="0" stopColor="#114a8b"/>
        <stop offset="1" stopColor="#0669bc"/>
      </linearGradient>
      <linearGradient id="az-grad-2" x1="-1023.725" y1="108.083" x2="-1029.98" y2="105.968" gradientTransform="matrix(1 0 0 -1 1075 158)" gradientUnits="userSpaceOnUse">
        <stop offset="0" stopOpacity=".3"/>
        <stop offset=".071" stopOpacity=".2"/>
        <stop offset=".321" stopOpacity=".1"/>
        <stop offset=".623" stopOpacity=".05"/>
        <stop offset="1" stopOpacity="0"/>
      </linearGradient>
      <linearGradient id="az-grad-3" x1="-1027.165" y1="147.642" x2="-997.482" y2="68.561" gradientTransform="matrix(1 0 0 -1 1075 158)" gradientUnits="userSpaceOnUse">
        <stop offset="0" stopColor="#3ccbf4"/>
        <stop offset="1" stopColor="#2892df"/>
      </linearGradient>
    </defs>
    <path d="M33.338 6.544h26.038l-27.03 80.087a4.152 4.152 0 0 1-3.933 2.824H8.149a4.145 4.145 0 0 1-3.928-5.47L29.404 9.368a4.152 4.152 0 0 1 3.934-2.824z" fill="url(#az-grad-1)"/>
    <path d="M71.175 60.261H33.376a1.91 1.91 0 0 0-1.305 3.308l24.267 22.679a4.171 4.171 0 0 0 2.838 1.107h21.44z" fill="#1f9cf0"/>
    <path d="M33.338 6.544a4.118 4.118 0 0 0-3.943 2.879L4.252 83.917a4.14 4.14 0 0 0 3.908 5.538h20.787a4.443 4.443 0 0 0 3.41-2.9l5.014-14.777 17.91 16.705a4.237 4.237 0 0 0 2.666.934h23.254l-10.224-29.134-29.781.007L51.369 6.544z" fill="url(#az-grad-2)"/>
    <path d="M66.595 9.368a4.145 4.145 0 0 0-3.928-2.824H33.648a4.146 4.146 0 0 1 3.928 2.824l25.184 74.62a4.146 4.146 0 0 1-3.928 5.467h29.02a4.146 4.146 0 0 0 3.927-5.467z" fill="url(#az-grad-3)"/>
  </svg>
);

const LinkedInIcon: React.FC = () => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="34" height="34">
    <path fill="#0A66C2" d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433a2.062 2.062 0 0 1-2.063-2.065 2.064 2.064 0 1 1 2.063 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z"/>
  </svg>
);

const ISC2Icon: React.FC = () => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 60 60" width="36" height="36">
    <rect width="60" height="60" rx="4" fill="#1a1f5e"/>
    <text x="50%" y="36%" dominantBaseline="middle" textAnchor="middle"
      fontFamily="Arial, sans-serif" fontWeight="bold" fontSize="13" fill="#ffffff" letterSpacing="1">
      (ISC)
    </text>
    <text x="50%" y="68%" dominantBaseline="middle" textAnchor="middle"
      fontFamily="Arial, sans-serif" fontWeight="bold" fontSize="16" fill="#00aaff">
      ²
    </text>
  </svg>
);

/* ── Data ── */

const certifications = [
  {
    title: 'AWS Cloud Practitioner',
    issuer: 'Amazon Web Services',
    year: '2023',
    accent: '#FF9900',
    icon: null,
    badge: 'AWS',
    iconType: 'aws' as const,
  },
  {
    title: 'Azure Fundamentals AZ-900',
    issuer: 'Microsoft',
    year: '2023',
    accent: '#0078d4',
    icon: null,
    badge: 'AZ-900',
    iconType: 'azure' as const,
  },
  {
    title: 'Certified in Cybersecurity (CC)',
    issuer: 'ISC2',
    year: '2023',
    accent: '#1a1f5e',
    icon: null,
    badge: 'CC',
    iconType: 'isc2' as const,
  },
  {
    title: 'Technical Security Audit & Assessment',
    issuer: 'LinkedIn Learning',
    year: '2023',
    accent: '#0a66c2',
    icon: null,
    badge: 'LI',
    iconType: 'linkedin' as const,
  },
  {
    title: 'PowerShell: Automating IT Administration',
    issuer: 'LinkedIn Learning',
    year: '2023',
    accent: '#0a66c2',
    icon: null,
    badge: 'LI',
    iconType: 'linkedin' as const,
  },
  {
    title: 'Cybersecurity with Cloud Computing',
    issuer: 'LinkedIn Learning',
    year: '2022',
    accent: '#0a66c2',
    icon: null,
    badge: 'LI',
    iconType: 'linkedin' as const,
  },
];

const ongoingCertifications = [
  {
    title: 'Azure Administrator Associate AZ-104',
    issuer: 'Microsoft',
    year: '2024',
    accent: '#0078d4',
    icon: null,
    badge: 'AZ-104',
    iconType: 'azure' as const,
  },
];

/* ── Helpers ── */

const SectionTitle: React.FC<{ title: string; count?: string; top?: boolean }> = ({ title, count, top }) => (
  <div style={{ marginBottom: 20 }}>
    <h2 style={{
      fontSize: top ? 48 : 28,
      fontFamily: '"Abril Fatface", Georgia, serif',
      fontWeight: 400,
      color: '#1a1a1a',
      marginBottom: 4,
      lineHeight: 1,
    }}>{title}</h2>
    {count && <div style={{ fontSize: 13, color: '#888', letterSpacing: 1.5, textTransform: 'uppercase', marginBottom: 6 }}>{count}</div>}
    <div style={{ height: 1, background: '#ccc' }} />
  </div>
);

type Cert = typeof certifications[0];
type OngoingCert = typeof ongoingCertifications[0];

const renderIcon = (cert: Cert | OngoingCert) => {
  switch (cert.iconType) {
    case 'aws':      return <AWSIcon />;
    case 'azure':    return <AzureIcon />;
    case 'isc2':     return <ISC2Icon />;
    case 'linkedin': return <LinkedInIcon />;
    default:         return null;
  }
};

const usesCustomIcon = (cert: Cert | OngoingCert) =>
  cert.iconType === 'aws' || cert.iconType === 'azure' || cert.iconType === 'isc2' || cert.iconType === 'linkedin';

const badgeTextColor = (cert: Cert | OngoingCert) => {
  if (cert.iconType === 'aws')      return '#FF9900';
  if (cert.iconType === 'azure')    return '#0078d4';
  if (cert.iconType === 'isc2')     return '#1a1f5e';
  if (cert.iconType === 'linkedin') return '#0A66C2';
  return '#fff';
};

const CertRow: React.FC<{ cert: Cert | OngoingCert; ongoing?: boolean }> = ({ cert, ongoing }) => {
  const custom = usesCustomIcon(cert);
  return (
    <div style={{
      display: 'flex', alignItems: 'center',
      border: `1px solid ${ongoing ? '#e8a000' : '#e8e8e8'}`, overflow: 'hidden',
    }}>
      <div style={{
        width: 72, flexShrink: 0,
        background: custom ? '#fff' : ongoing ? '#b8860b' : cert.accent,
        padding: '14px 0',
        display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 4,
        borderRight: custom ? '1px solid #e8e8e8' : 'none',
      }}>
        {renderIcon(cert)}
        <span style={{ fontSize: 9, fontWeight: 'bold', color: custom ? badgeTextColor(cert) : '#fff', letterSpacing: 1 }}>
          {cert.badge}
        </span>
      </div>
      <div style={{ flex: 1, padding: '12px 16px', background: ongoing ? '#fffbf0' : '#fafafa' }}>
        <div style={{ fontSize: 12, fontWeight: 'bold', color: '#222', marginBottom: 3 }}>{cert.title}</div>
        <div style={{ fontSize: 11, color: '#555' }}>{cert.issuer}</div>
      </div>
      <div style={{
        width: ongoing ? 80 : 60, flexShrink: 0,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        background: ongoing ? '#fff8e0' : '#f0f0f0',
        borderLeft: `1px solid ${ongoing ? '#e8c96a' : '#e8e8e8'}`, alignSelf: 'stretch',
      }}>
        {ongoing
          ? <span style={{ fontSize: 9, color: '#9a6a00', fontWeight: 'bold', textAlign: 'center', lineHeight: 1.3 }}>IN{'\n'}PROGRESS</span>
          : <span style={{ fontSize: 11, color: '#777', fontWeight: 'bold' }}>{cert.year}</span>
        }
      </div>
    </div>
  );
};

/* ── Page ── */

const Certifications: React.FC = () => (
  <div style={{ padding: '28px 40px', maxWidth: 740 }}>
    <SectionTitle title="Certifications" count={`${certifications.length} certifications`} top />
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginBottom: 40 }}>
      {certifications.map((cert) => (
        <CertRow key={cert.title} cert={cert} />
      ))}
    </div>

    <SectionTitle title="Ongoing Learning" count={`${ongoingCertifications.length} in progress`} />
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
      {ongoingCertifications.map((cert) => (
        <CertRow key={cert.title} cert={cert} ongoing />
      ))}
    </div>
  </div>
);

export default Certifications;
